example.code:
// Good - explicit contract
@Nullable
public User findUser(String id) {
    return cache.get(id);
}

// Good - non-null by default
public User requireUser(String id) {
    return Objects.requireNonNull(cache.get(id));
}

// Good
public Optional<User> findUser(String id) {
    return Optional.ofNullable(cache.get(id));
}

// Bad
public User findUser(String id) {
    return cache.get(id); // may be null
}

@Override
public boolean equals(Object other) {
    if (this == other) return true;
    if (!(other instanceof User)) return false;
    User that = (User) other;
    return Objects.equals(id, that.id);
}

@Override
public int hashCode() {
    return Objects.hash(id);
}

@Override
public int compareTo(User other) {
    return this.id.compareTo(other.id);
}

// Good
public record Money(String currency, long cents) {}

// Avoid verbose boilerplate
public final class Money {
    private final String currency;
    private final long cents;
    // constructors, equals, hashCode, toString...
}
